using UnityEngine;

/// <summary>
/// Rugido (Leão "rugido que atordoa inimigos pequenos", Tigre "rugido de
/// pressão" — P5): atordoa inimigos num raio à volta do player, via
/// EnemyStatusEffectReceiver (P7 — respeita canBeStunned e imunidades).
///
/// "maxEnemyWeight" limita o efeito a inimigos pequenos/leves (ficha do Leão).
/// Activado via PrimaryAbility.Roar (AbilityRouter → TryRoar).
/// </summary>
public class RoarAbility : MonoBehaviour, IFormAbility, IAbility, IActiveAbility
{
    [Header("Rugido")]
    public float radius = 4f;

    [Tooltip("Duração do atordoamento aplicado.")]
    public float stunDuration = 2f;

    [Tooltip("Peso máximo (EnemyData.stats.weight) dos inimigos afectados — 'atordoa inimigos pequenos'. 0 = afecta todos.")]
    [Min(0f)] public float maxEnemyWeight = 3f;

    public float cooldown = 4f;

    [Header("Feedback (opcional)")]
    public GameObject roarVfxPrefab;
    public AudioClip roarSound;

    private bool enabledForForm;
    private float cooldownTimer;

    private void Update()
    {
        if (cooldownTimer > 0f) cooldownTimer -= Time.deltaTime;
    }

    public void ConfigureFromForm(AnimalFormData form)
    {
        enabledForForm = form != null && form.primaryAbility == PrimaryAbility.Roar;
        cooldownTimer = 0f;
    }

    /// <summary>Ruge (AbilityRouter — PrimaryAbility.Roar).</summary>
    public void TryRoar()
    {
        if (!enabledForForm || cooldownTimer > 0f) return;

        cooldownTimer = cooldown;

        if (roarVfxPrefab != null)
            Instantiate(roarVfxPrefab, transform.position, Quaternion.identity);

        if (roarSound != null)
            AudioManager.Instance?.PlaySEAtPoint(roarSound, transform.position);

        var hits = Physics2D.OverlapCircleAll(transform.position, radius);

        foreach (var hit in hits)
        {
            var receiver = hit.GetComponent<EnemyStatusEffectReceiver>();
            if (receiver == null) continue;

            // Só inimigos pequenos/leves (ficha do Leão).
            if (maxEnemyWeight > 0f)
            {
                var ctrl = hit.GetComponent<EnemyController>();
                if (ctrl != null && ctrl.Data != null && ctrl.Data.stats.weight > maxEnemyWeight) continue;
            }

            receiver.ApplyEffect(EnemyStatusEffect.Stun, stunDuration);
        }
    }

    private void OnDrawGizmosSelected()
    {
        Gizmos.color = new Color(1f, 0.8f, 0.2f, 0.5f);
        Gizmos.DrawWireSphere(transform.position, radius);
    }

    // ---- IAbility / IActiveAbility (Tarefa #34 — HUD) ----
    // Instantânea, sem estado persistente — só o cooldown importa para a HUD.
    void IAbility.Activate() => TryRoar();
    void IAbility.Release() { }
    public void Cancel(AbilityCancelReason reason) { }
    public float CooldownRemaining => Mathf.Max(0f, cooldownTimer);
    bool IAbility.IsActive => false;
    public float CooldownDuration => cooldown;
    public bool CanActivate => enabledForForm && cooldownTimer <= 0f;

    /// <summary>AnimalsDebugPanel — zera o cooldown do rugido.</summary>
    public void ResetCooldown() => cooldownTimer = 0f;
}
